289→export function FloatingNotesView() {
290→  const nav = useNavigation();
291→  const [entries, setEntries] = useState<NoteEntry[]>([]);
292→  const [query, setQuery] = useState('');
293→  const [selectedIndex, setSelectedIndex] = useState(0);
294→  const [actionsOpen, setActionsOpen] = useState(false);
295→  const [subView, setSubView] = useState<NoteSubView>('list');
296→  const [editingNote, setEditingNote] = useState<NoteEntry | undefined>();
297→  const { items: hudItems, show: showHUD } = useHUD();
298→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
299→
300→  useEffect(() => {
301→    let aborted = false;
302→
303→    noteDb
304→      .getAll()
305→      .then(rows => {
306→        if (aborted) return;
307→        if (rows.length > 0) {
308→          setEntries(rows.map(rowToEntry));
309→        } else if (!isTauri) {
310→          const mock = MOCK_NOTE_ENTRIES.map(e => ({ ...e }));
311→          setEntries(mock);
312→          Promise.all(mock.map(e => noteDb.insert(entryToRow(e)))).catch(
313→            console.error,
314→          );
315→        }
316→      })
317→      .catch(err => {
318→        console.error('Failed to load notes:', err);
319→        if (!isTauri && !aborted) {
320→          setEntries(MOCK_NOTE_ENTRIES.map(e => ({ ...e })));
321→        }
322→      });
323→
324→    return () => {
325→      aborted = true;
326→    };
327→  }, []);
328→
329→  const dbSearchFn = useCallback((q: string) => noteDb.search(q), []);
330→  const { results: ftsResults, invalidate: invalidateFts } = useDbSearch(
331→    query,
332→    dbSearchFn,
333→    rowToEntry,
334→  );
335→
336→  const filtered = useMemo(() => {
337→    const items = ftsResults ?? entries;
338→    if (!ftsResults && query) {
339→      return items.filter(
340→        e => fuzzyMatch(query, e.title) || fuzzyMatch(query, e.content),
341→      );
342→    }
343→    return items;
344→  }, [
345→    entries,
346→    query,
347→    ftsResults,
348→  ]);
349→
350→  const totalItemCount = filtered.length;
351→
352→  useEffect(() => {
353→    if (totalItemCount === 0) {
354→      setSelectedIndex(0);
355→    } else {
356→      setSelectedIndex(prev =>
357→        prev >= totalItemCount ? totalItemCount - 1 : prev);
358→    }
359→  }, [totalItemCount]);
360→
361→  const selectedEntry = filtered[selectedIndex];
362→
363→  const handleQueryChange = useCallback((value: string) => {
364→    setQuery(value);
365→    setSelectedIndex(0);
366→    setActionsOpen(false);
367→  }, []);
368→
369→  const handleActiveIndexChange = useCallback((index: number) => {
370→    setSelectedIndex(index);
371→    setActionsOpen(false);
372→  }, []);
373→
374→  const handleOpen = useCallback(() => {
375→    if (!selectedEntry) return;
376→    setActionsOpen(false);
377→    setEditingNote(selectedEntry);
378→    setSubView('edit');
379→  }, [selectedEntry]);
380→
381→  const handleCopy = useCallback(() => {
382→    if (!selectedEntry) return;
383→    setActionsOpen(false);
384→    performCopy(selectedEntry.content, showHUD, {
385→      hudIcon: <NoteHUDIcon />,
386→    });
387→  }, [
388→    selectedEntry,
389→    showHUD,
390→  ]);
391→
392→  const handleCreate = useCallback(() => {
393→    setActionsOpen(false);
394→    setEditingNote(undefined);
395→    setSubView('create');
396→  }, []);
397→
398→  const handleDelete = useCallback(() => {
399→    if (!selectedEntry) return;
400→    const entryId = selectedEntry.id;
401→    const entryName = selectedEntry.title || 'Untitled';
402→    setActionsOpen(false);
403→    confirmAlert({
404→      title: `Delete "${entryName}"?`,
405→      message: 'This note will be permanently deleted.',
406→      icon: <TrashIcon size={32} />,
407→      primaryAction: {
408→        label: 'Delete',
409→        style: 'destructive',
410→        onAction: () => {
411→          setEntries(prev => prev.filter(e => e.id !== entryId));
412→          noteDb.delete(entryId).catch(console.error);
413→          invalidateFts();
414→          showHUD({
415→            icon: <NoteHUDIcon />,
416→            title: 'Note Deleted',
417→          });
418→        },
419→      },
420→      dismissAction: {
421→        label: 'Cancel',
422→        style: 'cancel',
423→        onAction: () => {},
424→      },
425→    });
426→  }, [
427→    selectedEntry,
428→    confirmAlert,
429→    showHUD,
430→    invalidateFts,
431→  ]);
432→
433→  const handleSave = useCallback(
434→    (title: string, content: string) => {
435→      const saveTime = new Date();
436→
437→      if (subView === 'edit' && editingNote) {
438→        const updatedEntry: NoteEntry = {
439→          ...editingNote,
440→          title: title || 'Untitled',
441→          content,
442→          updatedAt: saveTime,
443→        };
444→        setEntries(prev =>
445→          prev.map(e => (e.id === editingNote.id ? updatedEntry : e)));
446→        setEditingNote(updatedEntry);
447→        noteDb
448→          .update(editingNote.id, {
449→            title: title || 'Untitled',
450→            content,
451→          })
452→          .catch(console.error);
453→        invalidateFts();
454→      } else {
455→        const newEntry: NoteEntry = {
456→          id: crypto.randomUUID(),
457→          title: title || 'Untitled',
458→          content,
459→          createdAt: saveTime,
460→          updatedAt: saveTime,
461→        };
462→        setEntries(prev => [
463→          newEntry,
464→          ...prev,
465→        ]);
466→        noteDb.insert(entryToRow(newEntry)).catch(console.error);
467→        invalidateFts();
468→        setEditingNote(newEntry);
469→        setSubView('edit');
470→      }
471→    },
472→    [
473→      subView,
474→      editingNote,
475→      invalidateFts,
476→    ],
477→  );
478→
479→  const toggleActions = useCallback(() => {
480→    setActionsOpen(prev => !prev);
481→  }, []);
482→
483→  const closeActions = useCallback(() => {
484→    setActionsOpen(false);
485→  }, []);
486→
487→  const handleEscape = useCallback(() => {
488→    if (subView !== 'list') {
489→      setSubView('list');
490→      setEditingNote(undefined);
491→    }
492→  }, [subView]);
493→
494→  useKeyboardShortcut(
495→    {
496→      key: 'k',
497→      meta: true,
498→    },
499→    toggleActions,
500→    { enabled: subView === 'list' },
501→  );
502→  useKeyboardShortcut(
503→    {
504→      key: 'c',
505→      meta: true,
506→    },
507→    handleCopy,
508→    { enabled: subView === 'list' },
509→  );
510→  useKeyboardShortcut(
511→    {
512→      key: 'n',
513→      meta: true,
514→    },
515→    handleCreate,
516→    { enabled: subView === 'list' },
517→  );
518→  useKeyboardShortcut(
519→    {
520→      key: 'Backspace',
521→      meta: true,
522→    },
523→    handleDelete,
524→    { enabled: subView === 'list' },
525→  );
526→  useKeyboardShortcut({ key: 'Escape' }, handleEscape, {
527→    enabled: subView !== 'list',
528→    preventDefault: false,
529→  });
530→
531→  const dropdownSections: DropdownSection[] = useMemo(
532→    () => [
533→      {
534→        title: 'Actions',
535→        actions: [
536→          {
537→            label: 'Open',
538→            shortcut: <Kbd keys={['↵']} />,
539→            onClick: handleOpen,
540→          },
541→          createCopyAction(
542→            {
543→              content: selectedEntry?.content ?? '',
544→              title: 'Copy Content',
545→              shortcut: (
546→                <Kbd
547→                  keys={[
548→                    '⌘',
549→                    'C',
550→                  ]}
551→                />
552→              ),
553→              hudIcon: <NoteHUDIcon />,
554→            },
555→            showHUD,
556→          ),
557→          {
558→            label: 'Create Note',
559→            shortcut: (
560→              <Kbd
561→                keys={[
562→                  '⌘',
563→                  'N',
564→                ]}
565→              />
566→            ),
567→            onClick: handleCreate,
568→          },
569→        ],
570→      },
571→      {
572→        title: 'Danger Zone',
573→        actions: [
574→          {
575→            label: 'Delete',
576→            shortcut: (
577→              <Kbd
578→                keys={[
579→                  '⌘',
580→                  '⌫',
581→                ]}
582→              />
583→            ),
584→            onClick: handleDelete,
585→          },
586→        ],
587→      },
588→    ],
589→    [
590→      selectedEntry?.content,
591→      handleOpen,
592→      handleCreate,
593→      handleDelete,
594→      showHUD,
595→    ],
596→  );
597→
598→  const activeDescendantId =
599→    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;
600→
601→  if (subView !== 'list') {
602→    const formTitle = subView === 'edit' ? 'Edit Note' : 'Create Note';
603→    return (
604→      <>
605→        <SearchBar
606→          value=""
607→          onChange={() => {}}
608→          placeholder={formTitle}
609→          breadcrumbs={[
610→            ...nav.breadcrumbs,
611→            {
612→              label: 'Notes',
613→              onBack: handleEscape,
614→            },
615→          ]}
616→        />
617→        <div className="command-palette__body">
618→          <div className="command-palette__list-container">
619→            <NoteEditorView
620→              note={subView === 'edit' ? editingNote : undefined}
621→              onSave={handleSave}
622→            />
623→          </div>
624→        </div>
625→        <ActionPanel
626→          contextLabel={formTitle}
627→          actions={[
628→            {
629→              label: 'Save',
630→              shortcut: (
631→                <Kbd
632→                  keys={[
633→                    '⌘',
634→                    'S',
635→                  ]}
636→                />
637→              ),
638→            },
639→            {
640→              label: 'Preview',
641→              shortcut: (
642→                <Kbd
643→                  keys={[
644→                    '⌘',
645→                    '⇧',
646→                    'P',
647→                  ]}
648→                />
649→              ),
650→            },
651→          ]}
652→          dropdownOpen={false}
653→          dropdownSections={[]}
654→          onDropdownClose={() => {}}
655→        />
656→        <HUDContainer items={hudItems} />
657→        {alertState && <Alert {...alertState} onDismiss={dismissAlert} />}
658→      </>
659→    );
660→  }
661→
662→  return (
663→    <>
664→      <SearchBar
665→        value={query}
666→        onChange={handleQueryChange}
667→        placeholder="Search Notes..."
668→        activeDescendantId={activeDescendantId}
669→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
670→      />
671→      <div className="command-palette__body">
672→        <div className="command-palette__list-container">
673→          {totalItemCount === 0 ? (
674→            <EmptyState
675→              icon={<SearchEmptyIcon />}
676→              title="No Notes"
677→              description={
678→                query
679→                  ? 'Try a different search term'
680→                  : 'Create your first note with \u2318N'
681→              }
682→            />
683→          ) : (
684→            <List
685→              itemCount={totalItemCount}
686→              onActiveIndexChange={handleActiveIndexChange}
687→              onAction={handleOpen}
688→            >
689→              {(() => {
690→                const items: ReactNode[] = [];
691→                let globalIndex = 0;
692→                const renderNow = new Date();
693→                const oneDayAgo = renderNow.getTime() - 1000 * 60 * 60 * 24;
694→
695→                const recentItems = filtered.filter(
696→                  e => e.updatedAt.getTime() > oneDayAgo,
697→                );
698→                const olderItems = filtered.filter(
699→                  e => e.updatedAt.getTime() <= oneDayAgo,
700→                );
701→
702→                if (recentItems.length > 0) {
703→                  items.push(
704→                    <ListSection key="recent" title="Recent">
705→                      {recentItems.map(entry => {
706→                        const idx = globalIndex++;
707→                        return (
708→                          <ListItem
709→                            key={entry.id}
710→                            index={idx}
711→                            icon={<DocumentIcon />}
712→                            title={entry.title || 'Untitled'}
713→                            subtitle={truncateContent(entry.content, 60)}
714→                            accessories={[
715→                              {
716→                                text: formatRelativeDate(
717→                                  entry.updatedAt,
718→                                  renderNow,
719→                                ),
720→                                tooltip: entry.updatedAt.toLocaleString(),
721→                              },
722→                            ]}
723→                            query={query || undefined}
724→                          />
725→                        );
726→                      })}
727→                    </ListSection>,
728→                  );
729→                }
730→
731→                if (olderItems.length > 0) {
732→                  items.push(
733→                    <ListSection key="older" title="Older">
734→                      {olderItems.map(entry => {
735→                        const idx = globalIndex++;
736→                        return (
737→                          <ListItem
738→                            key={entry.id}
739→                            index={idx}
740→                            icon={<DocumentIcon />}
741→                            title={entry.title || 'Untitled'}
742→                            subtitle={truncateContent(entry.content, 60)}
743→                            accessories={[
744→                              {
745→                                text: formatRelativeDate(
746→                                  entry.updatedAt,
747→                                  renderNow,
748→                                ),
749→                                tooltip: entry.updatedAt.toLocaleString(),
750→                              },
751→                            ]}
752→                            query={query || undefined}
753→                          />
754→                        );
755→                      })}
756→                    </ListSection>,
757→                  );
758→                }
759→
760→                return items;
761→              })()}
762→            </List>
763→          )}
764→        </div>
765→      </div>
766→      <ActionPanel
767→        contextLabel="Notes"
768→        actions={[
769→          {
770→            label: 'Open',
771→            shortcut: <Kbd keys={['↵']} />,
772→          },
773→          {
774→            label: 'Actions',
