771→            <EditSnippetView
772→              snippet={subView === 'edit' ? editingSnippet : undefined}
773→              onSubmit={handleFormSubmit}
774→            />
775→          </div>
776→        </div>
777→        <ActionPanel
778→          contextLabel={formTitle}
779→          actions={[
780→            {
781→              label: 'Submit',
782→              shortcut: (
783→                <Kbd
784→                  keys={[
