797→      </>
798→    );
799→  }
800→
801→  return (
802→    <>
803→      <SearchBar
804→        value={query}
805→        onChange={handleQueryChange}
806→        placeholder="Search Snippets..."
807→        activeDescendantId={activeDescendantId}
808→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
809→        dropdown={
