  1→import {
  2→  type KeyboardEvent,
  3→  type ReactNode,
  4→  Fragment,
  5→  useEffect,
  6→  useRef,
  7→  useState,
  8→} from 'react';
  9→import type { BreadcrumbItem } from '../../hooks/use_navigation';
 10→import './search_bar.scss';
 11→
 12→interface SearchBarProps {
 13→  value: string;
 14→  onChange: (value: string) => void;
 15→  placeholder?: string;
 16→  cyclingPlaceholders?: string[];
 17→  activeDescendantId?: string;
 18→  breadcrumbs?: BreadcrumbItem[];
 19→  dropdown?: ReactNode;
 20→}
 21→
 22→const CYCLE_INTERVAL = 4000;
 23→const FADE_DURATION = 250;
 24→
 25→function useCyclingPlaceholder(
 26→  placeholders: string[] | undefined,
 27→  isActive: boolean,
 28→): {
 29→  text: string | undefined;
 30→  visible: boolean;
 31→} {
 32→  const [index, setIndex] = useState(0);
 33→  const [visible, setVisible] = useState(true);
 34→  const placeholdersRef = useRef(placeholders);
 35→
 36→  const contentsChanged =
 37→    !placeholders ||
 38→    !placeholdersRef.current ||
 39→    placeholders.length !== placeholdersRef.current.length ||
 40→    placeholders.some((p, i) => p !== placeholdersRef.current![i]);
 41→
 42→  if (contentsChanged) {
 43→    placeholdersRef.current = placeholders;
 44→  }
 45→
 46→  useEffect(() => {
 47→    setIndex(0);
 48→    setVisible(true);
 49→
 50→    const items = placeholdersRef.current;
 51→    if (!items || items.length <= 1 || !isActive) return;
 52→
 53→    let timeout: ReturnType<typeof setTimeout>;
 54→    const interval = setInterval(() => {
 55→      setVisible(false);
 56→      timeout = setTimeout(() => {
 57→        setIndex(prev => (prev + 1) % items.length);
 58→        setVisible(true);
 59→      }, FADE_DURATION);
 60→    }, CYCLE_INTERVAL);
 61→
 62→    return () => {
 63→      clearInterval(interval);
 64→      clearTimeout(timeout);
 65→    };
 66→  }, [
 67→    contentsChanged,
 68→    isActive,
 69→  ]);
 70→
 71→  if (!placeholders || placeholders.length === 0) {
 72→    return {
 73→      text: undefined,
 74→      visible: true,
 75→    };
 76→  }
 77→
 78→  return {
 79→    text: placeholders[index % placeholders.length],
 80→    visible,
 81→  };
 82→}
 83→
 84→export function SearchBar({
 85→  value,
 86→  onChange,
 87→  placeholder = 'Search...',
 88→  cyclingPlaceholders,
 89→  activeDescendantId,
 90→  breadcrumbs,
 91→  dropdown,
 92→}: SearchBarProps) {
 93→  const inputRef = useRef<HTMLInputElement>(null);
 94→  const isEmpty = !value;
 95→  const cycling = useCyclingPlaceholder(cyclingPlaceholders, isEmpty);
 96→  const hasCycling =
 97→    cyclingPlaceholders && cyclingPlaceholders.length > 1 && isEmpty;
 98→
 99→  useEffect(() => {
100→    inputRef.current?.focus();
101→  }, []);
102→
103→  function handleInputKeyDown(e: KeyboardEvent<HTMLInputElement>) {
104→    if (e.key !== 'Escape' || !breadcrumbs || breadcrumbs.length === 0) {
105→      return;
106→    }
107→
108→    e.preventDefault();
109→    if (value) {
110→      onChange('');
111→      return;
112→    }
113→
114→    for (let i = breadcrumbs.length - 1; i >= 0; i--) {
115→      const crumb = breadcrumbs[i];
116→      if (crumb?.onBack) {
117→        crumb.onBack();
118→        return;
119→      }
120→    }
121→  }
122→
123→  return (
124→    <div className="search-bar" role="search">
125→      <svg
126→        className="search-bar__icon"
127→        width="20"
128→        height="20"
129→        viewBox="0 0 20 20"
130→        fill="none"
131→        xmlns="http://www.w3.org/2000/svg"
132→      >
133→        <circle cx="9" cy="9" r="5.5" stroke="currentColor" strokeWidth="1.5" />
134→        <line
135→          x1="13.25"
136→          y1="13.25"
137→          x2="17.5"
138→          y2="17.5"
139→          stroke="currentColor"
140→          strokeWidth="1.5"
141→          strokeLinecap="round"
142→        />
