### 6. COMPLETE FLOATING NOTES COMPONENT (KEY SECTIONS)

**Essential component structure for Translator:**

```typescript
import {
  type ReactNode,
  useCallback,
  useEffect,
  useMemo,
  useState,
} from 'react';
import { useAlert } from '../../hooks/use_alert';
import { useHUD } from '../../hooks/use_hud';
import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
import { useNavigation } from '../../hooks/use_navigation';
import { ActionPanel } from '../action_panel/action_panel';
import { createCopyAction, performCopy } from '../action_panel/actions';
import type { DropdownSection } from '../action_panel/actions_dropdown';
import { Alert } from '../alert/alert';
import { EmptyState } from '../empty_state/empty_state';
import { HUDContainer } from '../hud/hud_container';
import { Kbd } from '../kbd/kbd';
import { List, ListItem, ListSection } from '../list';
import { SearchBar } from '../search_bar/search_bar';
import './translator_view.scss';

function TranslatorHUDIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      {/* Icon SVG */}
    </svg>
  );
}

export function TranslatorView() {
  const nav = useNavigation();
  const [query, setQuery] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [actionsOpen, setActionsOpen] = useState(false);
  const [entries, setEntries] = useState<TranslationEntry[]>([]);
  const { items: hudItems, show: showHUD } = useHUD();
  const { alertState, dismiss: dismissAlert } = useAlert();

  // Load initial data
  useEffect(() => {
    let aborted = false;
    // Load from database or mock data
    return () => {
      aborted = true;
    };
  }, []);

  // Handle query changes
  const handleQueryChange = useCallback((value: string) => {
    setQuery(value);
    setSelectedIndex(0);
    setActionsOpen(false);
  }, []);

  // Handle active item change
  const handleActiveIndexChange = useCallback((index: number) => {
    setSelectedIndex(index);
    setActionsOpen(false);
  }, []);

  // Copy translation action
  const handleCopy = useCallback(() => {
    if (!selectedEntry) return;
    setActionsOpen(false);
    performCopy(selectedEntry.translatedText, showHUD, {
      hudIcon: <TranslatorHUDIcon />,
    });
  }, [selectedEntry, showHUD]);

  // Keyboard shortcuts
  useKeyboardShortcut(
    { key: 'k', meta: true },
    () => setActionsOpen(prev => !prev),
  );
  useKeyboardShortcut(
    { key: 'c', meta: true },
    handleCopy,
  );

  // Action dropdown sections
  const dropdownSections: DropdownSection[] = useMemo(
    () => [
      {
        title: 'Actions',
        actions: [
          createCopyAction(
            {
              content: selectedEntry?.translatedText ?? '',
              title: 'Copy Translation',
              shortcut: <Kbd keys={['⌘', 'C']} />,
              hudIcon: <TranslatorHUDIcon />,
            },
            showHUD,
          ),
        ],
      },
    ],
    [selectedEntry?.translatedText, showHUD],
  );

  const activeDescendantId =
    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;

  return (
    <>
      <SearchBar
        value={query}
        onChange={handleQueryChange}
        placeholder="Search translations..."
        activeDescendantId={activeDescendantId}
        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
      />
      <div className="command-palette__body">
        <div className="command-palette__list-container">
          {totalItemCount === 0 ? (
            <EmptyState
              icon={<SearchEmptyIcon />}
              title="No translations"
              description="Enter text to translate"
            />
          ) : (
            <List
              itemCount={totalItemCount}
              onActiveIndexChange={handleActiveIndexChange}
              onAction={handleAction}
            >
              {entries.map((entry, idx) => (
                <ListItem
                  key={entry.id}
                  index={idx}
                  icon={<TranslatorHUDIcon />}
                  title={entry.sourceText}
                  subtitle={entry.translatedText}
                  query={query || undefined}
                />
              ))}
            </List>
          )}
        </div>
      </div>
      <ActionPanel
        contextLabel="Translator"
        actions={[
          {
            label: 'Copy',
            shortcut: <Kbd keys={['⌘', 'C']} />,
          },
          {
            label: 'Actions',
            shortcut: <Kbd keys={['⌘', 'K']} />,
          },
        ]}
        dropdownOpen={actionsOpen}
        dropdownSections={dropdownSections}
        onDropdownClose={() => setActionsOpen(false)}
      />
      <HUDContainer items={hudItems} />
      {alertState && <Alert {...alertState} onDismiss={dismissAlert} />}
    </>
  );
}
```

